const POLICY_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

export function quote(items: { type: string }[], context: QuoteContext): number {
  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return basePremium + POLICY_FEE;
}
